using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonModelTests
{
    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange - using Student since Person is abstract
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John"
        };

        // Act
        var fullName = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", fullName);
    }

    [TestMethod]
    public void FullName_WithSingleCharNames_FormatsCorrectly()
    {
        // Arrange
        var student = new Student
        {
            LastName = "X",
            FirstMidName = "Y"
        };

        // Act
        var fullName = student.FullName;

        // Assert
        Assert.AreEqual("X, Y", fullName);
    }

    [TestMethod]
    public void FullName_InstructorAlsoWorks()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Doe",
            FirstMidName = "Jane"
        };

        // Act
        var fullName = instructor.FullName;

        // Assert
        Assert.AreEqual("Doe, Jane", fullName);
    }
}

