using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_HasCorrectPageIndex()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_50Items_PageSize10_Has5TotalPages()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(5, result.TotalPages);
    }

    [TestMethod]
    public void Create_FirstPage_HasNoPreviousPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void Create_FirstPage_HasNextPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_LastPage_HasPreviousPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 5, 10);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void Create_LastPage_HasNoNextPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 5, 10);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_MiddlePage_HasBothPreviousAndNextPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ContainsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
    }

    [TestMethod]
    public void Create_SecondPage_ContainsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
    }

    [TestMethod]
    public void Create_LastPagePartial_ContainsRemainingItems()
    {
        // Arrange - 25 items, page size 10 = pages 1(10), 2(10), 3(5)
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void Create_SingleItem_SinglePage()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_ItemCountEqualsPageSize_HasSinglePage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasNextPage);
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPagesCorrectly_CeilingDivision()
    {
        // Arrange & Act - 11 items, page size 10 = ceil(11/10) = 2 pages
        var items = Enumerable.Range(1, 10).ToList();
        var paginatedList = new PaginatedList<int>(items, 11, 1, 10);

        // Assert
        Assert.AreEqual(2, paginatedList.TotalPages);
    }
}

