using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from the static queue
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _service.Dispose();
    }

    [TestMethod]
    public void SendNotification_CreatesNotificationWithCorrectEntityType()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
    }

    [TestMethod]
    public void SendNotification_CreatesNotificationWithCorrectEntityId()
    {
        // Arrange & Act
        _service.SendNotification("Course", "42", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("42", notification.EntityId);
    }

    [TestMethod]
    public void SendNotification_CreatesNotificationWithCorrectOperation()
    {
        // Arrange & Act
        _service.SendNotification("Department", "5", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Smith"));
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "99", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("99"));
    }

    [TestMethod]
    public void SendNotification_CreateOperation_MessageContainsCreated()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'Test Student' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_MessageContainsUpdated()
    {
        // Arrange & Act
        _service.SendNotification("Course", "1", "Chemistry", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_MessageContainsDeleted()
    {
        // Arrange & Act
        _service.SendNotification("Department", "1", "Engineering", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithUserName_UsesProvidedName()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("TestUser", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        // Assert
        var after = DateTime.Now;
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Act
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsInFifoOrder()
    {
        // Arrange
        _service.SendNotification("First", "1", EntityOperation.CREATE, "Admin");
        _service.SendNotification("Second", "2", EntityOperation.UPDATE, "Admin");
        _service.SendNotification("Third", "3", EntityOperation.DELETE, "Admin");

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.AreEqual("First", first!.EntityType);

        var second = _service.ReceiveNotification();
        Assert.AreEqual("Second", second!.EntityType);

        var third = _service.ReceiveNotification();
        Assert.AreEqual("Third", third!.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_RemovesFromQueue()
    {
        // Arrange
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        // Act
        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void SendNotification_ExceedingMaxQueueLength_EvictsOldEntries()
    {
        // Arrange & Act - send more than 500 notifications
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE, "Admin");
        }

        // Assert - count notifications remaining (should be <= 500)
        int count = 0;
        while (_service.ReceiveNotification() != null)
        {
            count++;
        }
        Assert.IsTrue(count <= 500, $"Queue should be capped at 500, but had {count} items");
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act - MarkAsRead is a no-op in this implementation but should not throw
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void SendNotification_WithNullDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "42", null, EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("42"));
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "7", "  ", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 7) has been updated", notification.Message);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Act - should not throw
        _service.Dispose();
        _service.Dispose();
    }

    [TestMethod]
    public void SendNotification_TwoArgOverload_SetsOperationCorrectly()
    {
        // Arrange & Act - test the overload without displayName
        _service.SendNotification("Instructor", "5", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        SeedStudents();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2022, 9, 1) },
            new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = new DateTime(2021, 9, 1) }
        );
        _context.SaveChanges();
    }

    // ===== Index Tests =====

    [TestMethod]
    public void Index_DefaultSort_ReturnsViewWithStudentsOrderedByLastName()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_ReturnsStudentsDescendingByLastName()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    public void Index_DateSort_ReturnsStudentsOrderedByDateAscending()
    {
        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Earliest date first
        Assert.AreEqual(new DateTime(2020, 9, 1), model[0].EnrollmentDate);
    }

    [TestMethod]
    public void Index_DateDescSort_ReturnsStudentsOrderedByDateDescending()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Latest date first
        Assert.AreEqual(new DateTime(2022, 9, 1), model[0].EnrollmentDate);
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersCorrectly()
    {
        // Act
        var result = _controller.Index(null, null, "Li", null) as ViewResult;

        // Assert
