    [TestMethod]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 6666, Title = "Test", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB > 5MB limit

        // Act
        var result = _controller.Create(course, mockFile) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        var error = _controller.ModelState["teachingMaterialImage"]!.Errors[0].ErrorMessage;
        Assert.IsTrue(error.Contains("5MB"));
    }

    [TestMethod]
    [DataRow(".jpg")]
    [DataRow(".jpeg")]
    [DataRow(".png")]
    [DataRow(".gif")]
    [DataRow(".bmp")]
    public void Create_Post_ValidImageExtension_DoesNotRejectExtension(string extension)
    {
        // Arrange
        var course = new Course { CourseID = 5555, Title = "Test", Credits = 3, DepartmentID = 1 };
        var mockFile = CreateMockFile($"test{extension}", 1024);

        // Act
        var result = _controller.Create(course, mockFile);

        // Assert - should either redirect (success) or have a file system error, but NOT an extension error
        if (result is ViewResult viewResult)
        {
            // If it failed, it should NOT be because of extension validation
            if (_controller.ModelState.ContainsKey("teachingMaterialImage"))
            {
                var error = _controller.ModelState["teachingMaterialImage"]!.Errors[0].ErrorMessage;
                Assert.IsFalse(error.Contains("valid image file"), $"Extension {extension} was incorrectly rejected");
            }
        }
    }

