    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new NotificationsController(_context);
        // Drain any leftover notifications from the static queue
        DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void DrainNotificationQueue()
    {
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
        service.Dispose();
    }

    // ===== GetNotifications Tests =====

    [TestMethod]
    public void GetNotifications_WhenNoNotifications_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
