    public void GetNotifications_WhenNotificationsExist_ReturnsNotifications()
    {
        // Arrange - Send a notification through a service instance that shares the static queue
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        service.Dispose();
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10Notifications()
    {
        // Arrange - Send more than 10 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE, "Admin");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
