    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var dept = new Department { Name = "Test Dept", Budget = 100000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 1001, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };

        // Act
        context.Courses.Add(course);
        context.SaveChanges();

        // Assert
        var retrieved = context.Courses.Find(1001);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Test Course", retrieved.Title);
        Assert.AreEqual(3, retrieved.Credits);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor { FirstMidName = "Test", LastName = "Instructor", HireDate = DateTime.Now };
        context.Instructors.Add(instructor);
        var dept = new Department { Name = "Dept", Budget = 100000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 2001, Title = "Course", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };

        // Act
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        // Assert
        var retrieved = context.CourseAssignments.Find(course.CourseID, instructor.ID);
        Assert.IsNotNull(retrieved);
    }

