        context.Instructors.Add(instructor);
        context.SaveChanges();

        var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };

        // Act
        context.OfficeAssignments.Add(office);
        context.SaveChanges();

        // Assert
        var retrieved = context.OfficeAssignments.Find(instructor.ID);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Room 101", retrieved.Location);
    }

    [TestMethod]
    public void SchoolContext_CanAddNotification()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = DateTime.Now,
            CreatedBy = "System",
            IsRead = false
        };

        // Act
        context.Notifications.Add(notification);
        context.SaveChanges();

        // Assert
        var retrieved = context.Notifications.First();
        Assert.AreEqual("Student", retrieved.EntityType);
        Assert.AreEqual("CREATE", retrieved.Operation);
        Assert.AreEqual("Test message", retrieved.Message);
    }

    [TestMethod]
    public void SchoolContext_StudentEnrollments_NavigationWorks()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now };
        context.Students.Add(student);
        var dept = new Department { Name = "D", Budget = 100, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 3001, Title = "C", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        context.Enrollments.Add(new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.A });
        context.SaveChanges();

        // Act
        var loaded = context.Students.Include(s => s.Enrollments).First(s => s.ID == student.ID);

        // Assert
        Assert.IsNotNull(loaded.Enrollments);
        Assert.AreEqual(1, loaded.Enrollments.Count);
        Assert.AreEqual(Grade.A, loaded.Enrollments.First().Grade);
    }
}

